class Solution {
public:
    int numMusicPlaylists(int n, int goal, int k) {
        const int MOD = 1e9 + 7;
        vector<vector<long long>> dp(n + 1, vector<long long>(goal + 1, 0));
        dp[0][0] = 1;
        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= goal; ++j) {
                dp[i][j] = (dp[i - 1][j - 1] * (n - i + 1) + dp[i][j - 1] * max(i - k, 0)) % MOD;
            }
        }
        return dp[n][goal];
    }
};
efficiency: HIGH
time complexity: O(n*goal)
space complexity: O(n*goal)
energy implications: LOW
explanation: Dynamic programming is used to efficiently compute the number of playlists by breaking down the problem into smaller subproblems and storing their results. The key insight is that a playlist of j songs with i distinct songs can be formed by either adding a new song (dp[i-1][j-1]*(n-i+1)) or replaying an existing song (dp[i][j-1]*max(i-k,0)). The results are stored in a 2D array dp and computed iteratively. 
